SELECT * FROM ingredients


        AND category = #{category}


        AND name LIKE CONCAT('%', #{keyword}, '%')


ORDER BY FIELD(category,'원두','유제품','시럽/소스','파우더','차류','소모품','기타'), name
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM ingredients


        AND category = #{category}


        AND name LIKE CONCAT('%', #{keyword}, '%')
